import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

const countryCodes = [
  { code: "+1", label: "USA (+1)" },
  { code: "+44", label: "UK (+44)" },
  { code: "+91", label: "India (+91)" },
  { code: "+61", label: "Australia (+61)" },
  { code: "+81", label: "Japan (+81)" },
  // Add more country codes as needed
];

export default function Login({ onLogin }) {
  const navigate = useNavigate();
  const [countryCode, setCountryCode] = useState("+91");
  const [phone, setPhone] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1); // 1: enter phone, 2: enter otp
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:5000";

  const requestOtp = async () => {
    setLoading(true);
    setError("");
    try {
      const contact = countryCode + phone;
      const res = await fetch(`${API_BASE}/api/auth/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ phone: contact }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        setStep(2);
      } else {
        setError(data.message || "Failed to send OTP");
      }
    } catch (e) {
      setError("Network error");
    }
    setLoading(false);
  };

  const verifyOtp = async () => {
    setLoading(true);
    setError("");
    try {
      const contact = countryCode + phone;
      const res = await fetch(`${API_BASE}/api/auth/verify-otp`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ phone: contact, otp }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        onLogin(data.user || { phone: contact });
      } else {
        setError(data.message || "Invalid OTP");
      }
    } catch (e) {
      setError("Network error");
    }
    setLoading(false);
  };

  const handlePhoneChange = (e) => {
    const value = e.target.value;
    if (/^\d*$/.test(value)) {
      setPhone(value);
    }
  };

  return (
    <div className="login-container" style={{ maxWidth: 400, margin: "auto", padding: 20, backgroundColor: "#1e1e2f", borderRadius: 12, color: "#fff" }}>
      {step === 1 && (
        <>
          <h2>Login</h2>
          <div style={{ display: "flex", marginBottom: 12 }}>
            <select
              value={countryCode}
              onChange={(e) => setCountryCode(e.target.value)}
              disabled={loading}
              style={{ padding: 12, borderRadius: 8, border: "none", outline: "none", fontSize: 16, marginRight: 8 }}
            >
              {countryCodes.map((c) => (
                <option key={c.code} value={c.code}>
                  {c.label}
                </option>
              ))}
            </select>
            <input
              type="text"
              placeholder="Phone number"
              value={phone}
              onChange={handlePhoneChange}
              disabled={loading}
              style={{ flex: 1, padding: 12, borderRadius: 8, border: "none", outline: "none", fontSize: 16 }}
            />
          </div>
          <button onClick={requestOtp} disabled={loading || phone.length !== 10} style={{ width: "100%", padding: 12, backgroundColor: "#00f0ff", border: "none", borderRadius: 8, color: "#000", fontWeight: "bold", cursor: "pointer" }}>
            {loading ? "Sending OTP..." : "Send OTP"}
          </button>
          <div style={{ marginTop: 12 }}>
            <button onClick={() => navigate('/register')} style={{ background: "none", border: "none", color: "#00f0ff", cursor: "pointer", textDecoration: "underline" }}>
              New user? Register here
            </button>
          </div>
          {error && <div style={{ marginTop: 12, color: "#ff4d4f" }}>{error}</div>}
        </>
      )}
      {step === 2 && (
        <>
          <h2>Enter OTP</h2>
          <input
            type="text"
            placeholder="Enter OTP"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            disabled={loading}
            style={{ width: "100%", padding: 12, marginBottom: 12, borderRadius: 8, border: "none", outline: "none", fontSize: 16 }}
          />
          <button onClick={verifyOtp} disabled={loading || !otp} style={{ width: "100%", padding: 12, backgroundColor: "#00f0ff", border: "none", borderRadius: 8, color: "#000", fontWeight: "bold", cursor: "pointer" }}>
            {loading ? "Verifying..." : "Verify OTP"}
          </button>
          {error && <div style={{ marginTop: 12, color: "#ff4d4f" }}>{error}</div>}
        </>
      )}
    </div>
  );
}
